 {"id":"asupersync-0el","title":"[Time] Implement Timer Wheel and Budget Integration","description":"# Timer Wheel and Budget Integration

## Overview
Efficient timer data structure and integration with Asupersync's budget system.

## Implementation Steps

### Step 1: Hierarchical Timing Wheel
```rust
/// Hierarchical timing wheel for efficient timer management
/// 
/// Provides O(1) insert and fire for timers within the wheel's range.
/// Uses a multi-level wheel for extended range with graceful degradation.
pub struct TimerWheel {
    /// Current time (wheel position)
    current: u64,
    /// Wheel levels (finest to coarsest)
    levels: [WheelLevel; 4],
    /// Pending timers beyond wheel range
    overflow: BinaryHeap<OverflowTimer>,
}

/// Single level of the timing wheel
struct WheelLevel {
    /// Slots in this level (e.g., 256 slots)
    slots: Vec<Vec<TimerEntry>>,
    /// Slot duration (e.g., 1ms, 256ms, 65536ms, 16777216ms)
    resolution: Duration,
    /// Current slot index
    cursor: usize,
}

impl TimerWheel {
    pub fn new() -> Self {
        Self {
            current: 0,
            levels: [
                WheelLevel::new(256, Duration::from_millis(1)),      // 256ms range
                WheelLevel::new(256, Duration::from_millis(256)),    // ~65s range
                WheelLevel::new(256, Duration::from_secs(65)),       // ~4.6h range
                WheelLevel::new(256, Duration::from_secs(16777)),    // ~50 days range
            ],
            overflow: BinaryHeap::new(),
        }
    }

    /// Insert timer with deadline
    pub fn insert(&mut self, deadline: Instant, waker: Waker) -> TimerHandle {
        let duration = deadline.saturating_duration_since(Instant::now());
        let nanos = duration.as_nanos() as u64;

        // Find appropriate level
        for (level_idx, level) in self.levels.iter_mut().enumerate() {
            let level_range = level.resolution.as_nanos() as u64 * level.slots.len() as u64;
            if nanos < level_range {
                return level.insert(nanos, waker);
            }
        }

        // Overflow
        let handle = self.overflow.push(OverflowTimer { deadline, waker });
        handle
    }

    /// Advance time and return expired timers
    pub fn advance(&mut self, duration: Duration) -> Vec<Waker> {
        let mut expired = Vec::new();
        let target = self.current + duration.as_nanos() as u64;

        while self.current < target {
            // Process level 0
            expired.extend(self.levels[0].tick());
            self.current += self.levels[0].resolution.as_nanos() as u64;

            // Cascade to higher levels
            for i in 1..self.levels.len() {
                if self.levels[i-1].cursor == 0 {
                    let demoted = self.levels[i].tick();
                    // Demote timers to lower level
                    for timer in demoted {
                        self.levels[i-1].insert_entry(timer);
                    }
                }
            }
        }

        // Check overflow
        while let Some(timer) = self.overflow.peek() {
            if timer.deadline.saturating_duration_since(Instant::now()).as_nanos() as u64 <= 0 {
                expired.push(self.overflow.pop().unwrap().waker);
            } else {
                break;
            }
        }

        expired
    }

    /// Cancel a timer
    pub fn cancel(&mut self, handle: TimerHandle) -> bool {
        // Mark as cancelled (lazy removal)
        // Implementation depends on handle type
        true
    }
}
```

### Step 2: Budget-Deadline Integration
```rust
use crate::types::Budget;

/// Extension trait for Budget deadline operations
pub trait BudgetTimeExt {
    /// Get remaining time until deadline
    fn remaining_time(&self) -> Option<Duration>;

    /// Create sleep that respects budget deadline
    fn deadline_sleep(&self) -> Option<Sleep>;

    /// Check if deadline has passed
    fn deadline_elapsed(&self) -> bool;
}

impl BudgetTimeExt for Budget {
    fn remaining_time(&self) -> Option<Duration> {
        self.deadline().map(|d| d.saturating_duration_since(Instant::now()))
    }

    fn deadline_sleep(&self) -> Option<Sleep> {
        self.deadline().map(sleep_until)
    }

    fn deadline_elapsed(&self) -> bool {
        self.deadline().map(|d| d <= Instant::now()).unwrap_or(false)
    }
}

/// Sleep that integrates with current scope's budget
pub async fn budget_sleep(duration: Duration) -> Result<(), Elapsed> {
    let cx = Cx::current();
    let budget = cx.budget();

    // Use shorter of requested duration or remaining budget
    let effective_duration = match budget.remaining_time() {
        Some(remaining) if remaining < duration => remaining,
        _ => duration,
    };

    if effective_duration.is_zero() {
        return Err(Elapsed::new());
    }

    sleep(effective_duration).await;

    // Check if we were cut short by budget
    if budget.deadline_elapsed() {
        Err(Elapsed::new())
    } else {
        Ok(())
    }
}

/// Timeout that respects budget deadline
pub async fn budget_timeout<F: Future>(
    duration: Duration,
    future: F,
) -> Result<F::Output, Elapsed> {
    let cx = Cx::current();
    let budget = cx.budget();

    // Use shorter of requested timeout or remaining budget
    let effective_timeout = match budget.remaining_time() {
        Some(remaining) if remaining < duration => remaining,
        _ => duration,
    };

    timeout(effective_timeout, future).await
}
```

### Step 3: Deadline Propagation
```rust
/// Create child scope with reduced deadline
pub fn with_deadline(deadline: Instant) -> impl FnOnce(Scope) -> Scope {
    move |scope| {
        let current_budget = scope.budget();
        let new_budget = current_budget.with_deadline(deadline);
        scope.with_budget(new_budget)
    }
}

/// Create child scope with timeout from now
pub fn with_timeout(duration: Duration) -> impl FnOnce(Scope) -> Scope {
    with_deadline(Instant::now() + duration)
}

// Usage:
// scope.spawn_with(with_timeout(Duration::from_secs(30)), async { ... })
```

### Step 4: Deadline Propagation in Regions
```rust
impl Region {
    /// Propagate deadline to all children
    pub fn set_deadline(&mut self, deadline: Instant) {
        let current = self.budget();
        let new_deadline = match current.deadline() {
            Some(existing) => existing.min(deadline),
            None => deadline,
        };

        self.set_budget(current.with_deadline(new_deadline));

        // Propagate to child regions
        for child in self.children_mut() {
            child.set_deadline(new_deadline);
        }
    }
}
```

